const d = $input.first().json.body || $input.first().json;
const cop = (n) => '$' + Number(n || 0).toLocaleString('es-CO');
const fechaHora = `${d.fecha} · ${d.horaInicio}-${d.horaFin}`;
const wa = `¡Hola ${d.clienteNombre}! 🎉 Tu reserva en PAL COTEJO quedó *CONFIRMADA*.

🥅 ${d.cancha}
📅 ${fechaHora}
` +
  (d.tieneMesa ? `🍻 Mesa para ${d.personasMesa}
` : '') +
  `💵 Abono pagado: ${cop(d.montoAbonado)}
` +
  (Number(d.saldoEnCaja) > 0 ? `Saldo en caja: ${cop(d.saldoEnCaja)}
` : 'Pago completo ✅
') +
  `
Código: #${d.codigo}
¡Te esperamos! ⚽`;
const html = `<div style="font-family:sans-serif;max-width:480px"><h2 style="color:#16a34a">¡Reserva confirmada! ⚽</h2><p>Hola <b>${d.clienteNombre}</b>, tu reserva en <b>PAL COTEJO</b> quedó confirmada.</p><ul><li>🥅 ${d.cancha}</li><li>📅 ${fechaHora}</li>${d.tieneMesa ? `<li>🍻 Mesa para ${d.personasMesa}</li>` : ''}<li>💵 Abono pagado: ${cop(d.montoAbonado)}</li>${Number(d.saldoEnCaja) > 0 ? `<li>Saldo en caja: ${cop(d.saldoEnCaja)}</li>` : '<li>Pago completo ✅</li>'}</ul><p>Código: <b>#${d.codigo}</b></p></div>`;
return [{ json: { ...d, whatsappText: wa, emailHtml: html, emailAsunto: `Reserva confirmada #${d.codigo} - PAL COTEJO` } }];
